package com.oneil.wellness.walkplanner.data;import com.oneil.wellness.walkplanner.activity.*;import com.oneil.wellness.walkplanner.history.*;import java.time.*;import java.util.*;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;@Service public class DataDeletionService{private final HistoryRepository history;private final WalkActivityRepository activities;private final OpportunityOutcomeRepository outcomes;private final NotificationDeliveryRepository notifications;public DataDeletionService(HistoryRepository h,WalkActivityRepository a,OpportunityOutcomeRepository o,NotificationDeliveryRepository n){history=h;activities=a;outcomes=o;notifications=n;}@Transactional public long recommendations(LocalDate from,LocalDate to,String timezone){if(from==null||to==null||to.isBefore(from))throw new IllegalArgumentException("A valid inclusive date range is required.");ZoneId zone=ZoneId.of(timezone==null||timezone.isBlank()?"UTC":timezone);return history.deleteByCapturedAtBetween(from.atStartOfDay(zone).toInstant(),to.plusDays(1).atStartOfDay(zone).toInstant());}@Transactional public long notifications(){long n=notifications.count();notifications.deleteAllInBatch();return n;}@Transactional public long activities(){long n=activities.count();activities.deleteAllInBatch();return n;}@Transactional public Map<String,Long> all(){long a=activities.count(),o=outcomes.count(),n=notifications.count(),h=history.count();activities.deleteAllInBatch();outcomes.deleteAllInBatch();notifications.deleteAllInBatch();history.deleteAllInBatch();return Map.of("activities",a,"outcomes",o,"notifications",n,"recommendations",h);}}
